use std::fmt;

#[derive(Debug)]
pub struct BatchDownload {
    file_sizes: Vec<u64>,
    available_disk_space: u64,
}

#[derive(Debug, PartialEq)]
pub enum BatchDownloadError {
    InsufficientDiskSpace { required: u64, available: u64 },
    EmptyBatch,
    Overflow,
}

impl fmt::Display for BatchDownloadError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            BatchDownloadError::InsufficientDiskSpace { required, available } => {
                write!(
                    f,
                    "Insufficient disk space: required {} bytes, but only {} bytes available",
                    required, available
                )
            }
            BatchDownloadError::EmptyBatch => write!(f, "No files in the download batch"),
            BatchDownloadError::Overflow => write!(f, "Total file size overflowed u64"),
        }
    }
}

impl BatchDownload {
    pub fn new(file_sizes: Vec<u64>, available_disk_space: u64) -> Self {
        BatchDownload {
            file_sizes,
            available_disk_space,
        }
    }

    /// Calculate the total file size using regular (checked) addition.
    /// Returns an error if the sum overflows u64.
    pub fn calculate_total_size_checked(&self) -> Result<u64, BatchDownloadError> {
        if self.file_sizes.is_empty() {
            return Err(BatchDownloadError::EmptyBatch);
        }

        let mut total: u64 = 0;
        for &size in &self.file_sizes {
            total = total.checked_add(size).ok_or(BatchDownloadError::Overflow)?;
        }
        Ok(total)
    }

    /// Calculate the total file size using wrapping_add for maximum performance.
    /// Note: This will silently wrap around on overflow, so use only when you
    /// are confident that the total won't exceed u64::MAX.
    pub fn calculate_total_size_wrapping(&self) -> Result<u64, BatchDownloadError> {
        if self.file_sizes.is_empty() {
            return Err(BatchDownloadError::EmptyBatch);
        }

        let total = self
            .file_sizes
            .iter()
            .fold(0u64, |acc, &size| acc.wrapping_add(size));
        Ok(total)
    }

    /// Check whether the batch of downloads fits within the available disk space.
    pub fn check_disk_space(&self) -> Result<u64, BatchDownloadError> {
        let total = self.calculate_total_size_checked()?;
        if total > self.available_disk_space {
            Err(BatchDownloadError::InsufficientDiskSpace {
                required: total,
                available: self.available_disk_space,
            })
        } else {
            Ok(total)
        }
    }

    /// Returns the number of files in the batch.
    pub fn file_count(&self) -> usize {
        self.file_sizes.len()
    }

    /// Returns a human-readable string for a byte count.
    pub fn format_bytes(bytes: u64) -> String {
        const KB: u64 = 1024;
        const MB: u64 = KB * 1024;
        const GB: u64 = MB * 1024;
        const TB: u64 = GB * 1024;

        if bytes >= TB {
            format!("{:.2} TB", bytes as f64 / TB as f64)
        } else if bytes >= GB {
            format!("{:.2} GB", bytes as f64 / GB as f64)
        } else if bytes >= MB {
            format!("{:.2} MB", bytes as f64 / MB as f64)
        } else if bytes >= KB {
            format!("{:.2} KB", bytes as f64 / KB as f64)
        } else {
            format!("{} bytes", bytes)
        }
    }
}

/// Convenience function: sum file sizes and check against available disk space.
pub fn calculate_total_file_size(
    file_sizes: Vec<u64>,
    available_disk_space: u64,
) -> Result<u64, BatchDownloadError> {
    let batch = BatchDownload::new(file_sizes, available_disk_space);
    batch.check_disk_space()
}

fn main() {
    // Example: downloading several files
    let file_sizes = vec![
        1_500_000_000, // 1.5 GB
        750_000_000,   // 750 MB
        2_200_000_000, // 2.2 GB
        500_000_000,   // 500 MB
    ];
    let available_space: u64 = 10_000_000_000; // 10 GB

    match calculate_total_file_size(file_sizes.clone(), available_space) {
        Ok(total) => {
            println!("Batch contains {} files", file_sizes.len());
            println!("Total download size: {}", BatchDownload::format_bytes(total));
            println!(
                "Available disk space: {}",
                BatchDownload::format_bytes(available_space)
            );
            println!(
                "Remaining after download: {}",
                BatchDownload::format_bytes(available_space - total)
            );
        }
        Err(e) => {
            eprintln!("Download batch error: {}", e);
        }
    }

    // Example with insufficient disk space
    let large_files = vec![5_000_000_000, 4_000_000_000, 3_000_000_000];
    let small_disk: u64 = 8_000_000_000;

    match calculate_total_file_size(large_files, small_disk) {
        Ok(total) => {
            println!("Total size: {}", BatchDownload::format_bytes(total));
        }
        Err(e) => {
            eprintln!("Download batch error: {}", e);
        }
    }
}

